const body = $input.first().json;

// Required fields check
const required = ['client_name', 'email', 'service'];
const missing = required.filter(f => !body[f] || body[f].trim() === '');
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Prepare enriched record
const intakeDate = new Date().toISOString().split('T')[0];
const followUpDate = new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

return [{
  json: {
    client_name: body.client_name.trim(),
    email: body.email.trim().toLowerCase(),
    service: body.service.trim(),
    phone: body.phone || '',
    notes: body.notes || '',
    intake_date: intakeDate,
    follow_up_date: followUpDate,
    docs_received: false,
    last_reminder: ''
  }
}];
